mapper.select:

AND EXISTS (
    SELECT 1 FROM audio_folder_relation afr
    WHERE afr.audio_id = ai.id AND afr.folder_id = #{folderId}
)


AND EXISTS (
    SELECT 1 FROM audio_like al
    WHERE al.audio_id = ai.id AND al.user_id = #{userId}
)


AND EXISTS (
    SELECT 1 FROM play_history ph 
    WHERE ph.audio_id = ai.id AND ph.user_id = #{userId}
)
ORDER BY ph.update_time DESC
